const data = $input.first().json;

// Extrair e sanitizar campos
const sanitize = (str) => String(str || '').replace(/'/g, "''").substring(0, 255);

const nomeEmpresa  = sanitize(data['Nome da empresa']);
const numero       = sanitize(data['WhatsApp (com DDI e DDD, só números)']).replace(/\D/g, '').substring(0, 20);
const responsavel  = sanitize(data['Nome do responsável']);
const setorRaw     = data['Setor principal'] || 'Comercial / Vendas';

if (!nomeEmpresa || !numero || !responsavel) {
  throw new Error('Campos obrigatórios ausentes: nome, WhatsApp ou responsável');
}

if (!/^\d{10,15}$/.test(numero)) {
  throw new Error('Número de WhatsApp inválido. Use apenas dígitos com DDI e DDD. Ex: 5516988230361');
}

// Mapear setor para enum do banco
const setorMap = {
  'Comercial / Vendas': 'comercial',
  'Atendimento / Recepção': 'atendimento',
  'Operacional': 'operacional',
  'Marketing': 'marketing'
};
const setor = setorMap[setorRaw] || 'comercial';

// Gerar slug e instance_name (URL-safe, sem acentos)
const slug = nomeEmpresa
  .toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-+|-+$/g, '')
  .substring(0, 40);

const instanceName = 'ml-' + slug;

return [{
  json: {
    nome_empresa:    nomeEmpresa,
    slug,
    instance_name:   instanceName,
    numero_whatsapp: numero,
    responsavel,
    setor,
    webhook_path:    '/ml/webhook/whatsapp'
  }
}];

const prep = $('Preparar Dados').first().json;
const evo  = $('Criar Instância Evolution').first().json;

const qrBase64     = evo?.qrcode?.base64 || null;
const instanceName = prep.instance_name;
const nomeEmpresa  = prep.nome_empresa;

const passos = `
  <div class="step"><div class="num">1</div><div class="step-text">Abra o <strong>WhatsApp</strong> no celular da empresa</div></div>
  <div class="step"><div class="num">2</div><div class="step-text">Toque em <strong>⋮ Menu → Aparelhos conectados</strong></div></div>
  <div class="step"><div class="num">3</div><div class="step-text">Toque em <strong>Conectar um aparelho</strong></div></div>
  <div class="step"><div class="num">4</div><div class="step-text">Aponte a câmera para o <strong>QR Code acima</strong></div></div>
`;

const css = `
  body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #f0f4ff; display: flex; justify-content: center; align-items: center; min-height: 100vh; margin: 0; }
  .card { background: white; border-radius: 16px; padding: 40px; max-width: 440px; width: 90%; text-align: center; box-shadow: 0 4px 24px rgba(99,102,241,0.12); }
  .logo { color: #6366f1; font-size: 22px; font-weight: 700; margin-bottom: 4px; }
  .subtitle { color: #9ca3af; font-size: 13px; margin-bottom: 16px; }
  h2 { color: #1e1b4b; margin: 0 0 8px; font-size: 20px; }
  p { color: #6b7280; font-size: 14px; line-height: 1.6; margin: 0 0 16px; }
  .qr { margin: 20px auto; background: #f9fafb; border-radius: 12px; padding: 16px; display: inline-block; }
  .qr img { width: 220px; height: 220px; border-radius: 8px; display: block; }
  .steps { text-align: left; margin-top: 20px; }
  .step { display: flex; gap: 12px; align-items: flex-start; margin-bottom: 10px; }
  .num { background: #6366f1; color: white; border-radius: 50%; width: 26px; height: 26px; min-width: 26px; display: flex; align-items: center; justify-content: center; font-size: 13px; font-weight: 600; }
  .step-text { color: #374151; font-size: 14px; line-height: 1.5; padding-top: 3px; }
  .alert { margin-top: 20px; background: #fef3c7; border-radius: 8px; padding: 12px 16px; font-size: 13px; color: #92400e; }
  .success { margin-top: 20px; background: #d1fae5; border-radius: 8px; padding: 12px 16px; font-size: 13px; color: #065f46; }
  .spinner { margin: 30px auto; width: 40px; height: 40px; border: 4px solid #e5e7eb; border-top-color: #6366f1; border-radius: 50%; animation: spin 0.8s linear infinite; }
  @keyframes spin { to { transform: rotate(360deg); } }
`;

let html;

if (qrBase64) {
  html = `<!DOCTYPE html>
<html lang="pt-BR">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Conectar WhatsApp — ${nomeEmpresa}</title>
  <style>${css}</style>
</head>
<body>
  <div class="card">
    <div class="logo">⚡ ML Laboratory</div>
    <div class="subtitle">Onboarding</div>
    <h2>Escaneie para conectar</h2>
    <p><strong>${nomeEmpresa}</strong> — use o WhatsApp do celular da empresa para escanear o código abaixo.</p>
    <div class="qr">
      <img src="${qrBase64}" alt="QR Code WhatsApp" />
    </div>
    <div class="steps">${passos}</div>
    <div class="alert">⚠️ O QR Code expira em 60 segundos. Se expirar, volte e preencha o formulário novamente.</div>
    <div class="success" style="margin-top:12px">✅ Instância registrada: <code>${instanceName}</code></div>
  </div>
</body>
</html>`;
} else {
  // QR não chegou na resposta — redireciona para a URL de connect da Evolution
  const connectUrl = (process.env.EVOLUTION_API_URL || '') + '/instance/connect/' + instanceName;
  html = `<!DOCTYPE html>
<html lang="pt-BR">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Gerando QR Code...</title>
  <style>${css}</style>
  <script>
    setTimeout(() => { window.location.href = '${connectUrl}?apikey=' + ''; }, 3000);
  </script>
</head>
<body>
  <div class="card">
    <div class="logo">⚡ ML Laboratory</div>
    <div class="subtitle">Onboarding</div>
    <h2>Aguarde...</h2>
    <p>Sua instância está sendo criada. O QR Code aparecerá em instantes.</p>
    <div class="spinner"></div>
    <p style="font-size:12px;color:#9ca3af">Instância: <code>${instanceName}</code></p>
  </div>
</body>
</html>`;
}

return [{ json: { html, instance_name: instanceName } }];
